     1→import app from "./app";
     2→import { adminSeedStatus } from "./lib/store";
     3→import { logger } from "./lib/logger";
     4→import { startSweeper } from "./lib/sweeper";
     5→import { assertRequiredEnv } from "./lib/env";
     6→
     7→const { port } = assertRequiredEnv();
     8→
     9→if (adminSeedStatus.provisioned) {
    10→  logger.info(
    11→    { adminEmail: adminSeedStatus.email },
    12→    "[admin] Admin account provisioned from environment.",
    13→  );
    14→} else {
    15→  logger.warn(
    16→    { reason: adminSeedStatus.reason },
    17→    "[admin] No admin account provisioned. Set ADMIN_EMAIL and ADMIN_PASSWORD as Replit Secrets to enable admin login.",
    18→  );
    19→}
    20→
    21→// --------------------------------------------------------------------------
    22→// Crash guards
    23→// --------------------------------------------------------------------------
    24→// Without these, one unhandled promise rejection or thrown error anywhere
    25→// in the app kills the entire Node process — Railway then shows the request
    26→// as "crashed" and restarts the container, dropping in-flight requests.
    27→//
    28→// These handlers log the error with full context and keep the process
    29→// alive for transient/recoverable errors (a failed fetch, a bad DB query
    30→// that wasn't awaited correctly, etc). This is NOT a way to "fix" broken
    31→// code — a bug that throws will keep throwing every time it's hit. What
    32→// this buys you is that ONE bad request can't take down the whole server
    33→// for every other user.
    34→//
    35→// We deliberately do NOT exit on uncaughtException/unhandledRejection.
    36→// If the process reaches a truly unrecoverable state (e.g. out of memory),
    37→// Railway's healthcheck will detect the server stopped responding and
    38→// restart it anyway — that's the correct backstop, not a hard process.exit
    39→// here that would turn every transient error into a restart.
    40→process.on("uncaughtException", (err) => {
    41→  logger.error({ err: err.message, stack: err.stack }, "[crash-guard] uncaughtException — process kept alive");
    42→});
    43→
    44→process.on("unhandledRejection", (reason) => {
    45→  const err = reason instanceof Error ? reason : new Error(String(reason));
    46→  logger.error({ err: err.message, stack: err.stack }, "[crash-guard] unhandledRejection — process kept alive");
    47→});
    48→
    49→const server = app.listen(port, (err) => {
    50→  if (err) {
    51→    logger.error({ err }, "Error listening on port");
    52→    process.exit(1);
    53→  }
    54→
    55→  logger.info({ port }, "Server listening");
    56→  startSweeper();
    57→});
    58→
    59→// --------------------------------------------------------------------------
    60→// Graceful shutdown
    61→// --------------------------------------------------------------------------
    62→// Railway sends SIGTERM before stopping/restarting a container (deploys,
    63→// scaling, healthcheck failures). Without handling it, in-flight requests
    64→// get cut off mid-response. This stops accepting new connections, lets
    65→// existing requests finish (up to a timeout), then exits cleanly.
    66→let shuttingDown = false;
    67→
    68→function shutdown(signal: string) {
    69→  if (shuttingDown) return;
    70→  shuttingDown = true;
    71→  logger.info({ signal }, "[shutdown] received signal, closing gracefully");
    72→
    73→  const forceExitTimer = setTimeout(() => {
    74→    logger.warn("[shutdown] graceful shutdown timed out, forcing exit");
    75→    process.exit(1);
    76→  }, 10_000);
    77→
    78→  server.close((closeErr) => {
    79→    clearTimeout(forceExitTimer);
    80→    if (closeErr) {
    81→      logger.error({ err: closeErr.message }, "[shutdown] error during close");
    82→      process.exit(1);
    83→    }
    84→    logger.info("[shutdown] closed all connections, exiting cleanly");
    85→    process.exit(0);
    86→  });
    87→}
    88→
    89→process.on("SIGTERM", () => shutdown("SIGTERM"));
    90→process.on("SIGINT", () => shutdown("SIGINT"));
    91→

