     1→import express, { type Express } from "express";
     2→import cookieParser from "cookie-parser";
     3→import cors from "cors";
     4→import pinoHttp from "pino-http";
     5→import { rateLimit } from "express-rate-limit";
     6→import router from "./routes";
     7→import { logger } from "./lib/logger";
     8→import { attachSession } from "./lib/session";
     9→import { platformGate } from "./lib/platform-gate";
    10→import { env, isProduction } from "./lib/env";
    11→
    12→const app: Express = express();
    13→
    14→// Trust the platform's TLS-terminating reverse proxy in production so that
    15→// rate-limiting middleware keys on real client IPs rather than the proxy's IP.
    16→if (isProduction) {
    17→  app.set("trust proxy", 1);
    18→}
    19→
    20→if (isProduction && !env.SESSION_SECRET) {
    21→  throw new Error(
    22→    "SESSION_SECRET is required in production. Set it as an environment secret before starting the server.",
    23→  );
    24→}
    25→const SESSION_SECRET = env.SESSION_SECRET ?? "xpfx-dev-secret-change-me";
    26→
    27→app.use(
    28→  pinoHttp({
    29→    logger,
    30→    serializers: {
    31→      req(req) {
    32→        return { id: req.id, method: req.method, url: req.url?.split("?")[0] };
    33→      },
    34→      res(res) {
    35→        return { statusCode: res.statusCode };
    36→      },
    37→    },
    38→  }),
    39→);
    40→// Build an explicit allowlist of frontend origins from the Replit-provided
    41→// REPLIT_DOMAINS variable (comma-separated hostnames, e.g. "foo.repl.co,bar.repl.co").
    42→// In development all origins are permitted so local work is unimpeded.
    43→// In production, if REPLIT_DOMAINS is unset the allowlist is an empty Set,
    44→// which causes all credentialed cross-origin requests to be denied (fail-closed).
    45→const allowedOrigins: Set<string> | null = (() => {
    46→  if (!isProduction) return null; // null == allow-all in dev
    47→  const raw = env.REPLIT_DOMAINS ?? "";
    48→  const origins = new Set<string>();
    49→  for (const host of raw.split(",").map((s) => s.trim()).filter(Boolean)) {
    50→    origins.add(`https://${host}`);
    51→  }
    52→  if (origins.size === 0) {
    53→    logger.warn(
    54→      "REPLIT_DOMAINS is not set in production — credentialed cross-origin requests will be denied.",
    55→    );
    56→  }
    57→  return origins; // may be empty; empty == deny all cross-origin credentialed requests
    58→})();
    59→
    60→app.use(
    61→  cors({
    62→    origin(origin, callback) {
    63→      // No Origin header → server-to-server or same-origin request; pass through.
    64→      if (!origin) return callback(null, false);
    65→      if (allowedOrigins === null) return callback(null, true); // dev: allow all
    66→      if (allowedOrigins.has(origin)) return callback(null, true);
    67→      return callback(null, false); // unknown origin — deny credentials
    68→    },
    69→    credentials: true,
    70→  }),
    71→);
    72→
    73→// cookieParser must run before the CSRF middleware so req.signedCookies is
    74→// populated when we check for the session cookie below.
    75→app.use(cookieParser(SESSION_SECRET));
    76→
    77→// CSRF defense-in-depth: for cookie-authenticated mutating requests in
    78→// production, reject any Origin/Referer that is not on the allowlist.
    79→// This is a secondary layer; the CORS policy above is the primary guard.
    80→app.use((req, res, next) => {
    81→  if (
    82→    isProduction &&
    83→    allowedOrigins !== null &&
    84→    ["POST", "PUT", "PATCH", "DELETE"].includes(req.method)
    85→  ) {
    86→    const originHeader = req.headers.origin as string | undefined;
    87→    let checkOrigin: string | undefined = originHeader;
    88→    if (!checkOrigin && req.headers.referer) {
    89→      try {
    90→        checkOrigin = new URL(req.headers.referer as string).origin;
    91→      } catch {
    92→        checkOrigin = undefined;
    93→      }
    94→    }
    95→    // Only enforce when an origin is present and the request carries a session
    96→    // cookie — unauthenticated mutations (signup, login) don't need protection.
    97→    const hasCookie = Boolean(
    98→      req.signedCookies?.["xpfx_sid"] ?? req.cookies?.["xpfx_sid"],
    99→    );
   100→    if (checkOrigin && hasCookie && !allowedOrigins.has(checkOrigin)) {
   101→      res.status(403).json({ error: "Forbidden" });
   102→      return;
   103→    }
   104→  }
   105→  next();
   106→});
   107→
   108→// MoonPay signs the *raw* webhook body. Capture it as a Buffer on the
   109→// request before the JSON parser turns it into an object, so the
   110→// /moonpay/webhook handler can HMAC the exact bytes MoonPay signed.
   111→app.use(
   112→  "/api/moonpay/webhook",
   113→  express.raw({ type: "application/json", limit: "1mb" }),
   114→);
   115→app.use(
   116→  "/api/coinbase/webhook",
   117→  express.raw({ type: "application/json", limit: "1mb" }),
   118→);
   119→
   120→app.use(express.json());
   121→app.use(express.urlencoded({ extended: true }));
   122→app.use(attachSession);
   123→app.use(platformGate);
   124→
   125→// Rate-limit auth endpoints to resist brute-force and credential stuffing.
   126→// Counts attempts per IP. Limits are intentionally tight on high-risk paths.
   127→const authRateLimit = rateLimit({
   128→  windowMs: 15 * 60 * 1000, // 15-minute window
   129→  limit: 20,                 // max 20 auth attempts per IP per window
   130→  standardHeaders: "draft-7",
   131→  legacyHeaders: false,
   132→  message: { error: "Too many requests. Please try again later." },
   133→  skip: () => !isProduction,  // enforce only in production
   134→});
   135→
   136→const otpRateLimit = rateLimit({
   137→  windowMs: 15 * 60 * 1000,
   138→  limit: 10,                 // stricter limit for OTP verification and resend
   139→  standardHeaders: "draft-7",
   140→  legacyHeaders: false,
   141→  message: { error: "Too many requests. Please try again later." },
   142→  skip: () => !isProduction,
   143→});
   144→
   145→app.use("/api/auth/login", authRateLimit);
   146→app.use("/api/auth/signup", authRateLimit);
   147→app.use("/api/auth/verify-otp", otpRateLimit);
   148→app.use("/api/auth/resend-otp", otpRateLimit);
   149→
   150→// Rate-limit live-chat to prevent cost and availability abuse of the AI backend.
   151→// Keyed per authenticated user ID (falls back to IP for unauthenticated requests).
   152→const liveChatRateLimit = rateLimit({
   153→  windowMs: 60 * 1000,           // 1-minute window
   154→  limit: 10,                     // max 10 messages per user per minute
   155→  standardHeaders: "draft-7",
   156→  legacyHeaders: false,
   157→  keyGenerator: (req) => (req as typeof req & { userId?: string }).userId ?? req.ip ?? "unknown",
   158→  validate: { keyGeneratorIpFallback: false },
   159→  message: { error: "Too many messages. Please wait before sending another." },
   160→  skip: () => !isProduction,
   161→});
   162→
   163→app.use("/api/live-chat", liveChatRateLimit);
   164→
   165→app.use("/api", router);
   166→
   167→export default app;
   168→

