     1→/**
     2→ * Lazy PostgreSQL client + fire-and-forget shadow-write helper.
     3→ *
     4→ * The server starts and runs normally without DATABASE_URL — all calls to
     5→ * dbRun() / dbGet() become no-ops and warnings are logged once.  When
     6→ * DATABASE_URL is present the pool is initialised on first use.
     7→ *
     8→ * Rules:
     9→ *  - Never pass in-memory IDs to insert .values() — they are not valid UUIDs.
    10→ *    Let Drizzle auto-generate UUIDs via defaultRandom().
    11→ *  - dbRun() is fire-and-forget: the HTTP response is sent before it completes.
    12→ *  - dbGet() awaits and returns a typed fallback on error.
    13→ */
    14→import pg from "pg";
    15→import { drizzle } from "drizzle-orm/node-postgres";
    16→import * as schema from "@workspace/db/schema";
    17→import { logger } from "./logger";
    18→
    19→export type DbClient = ReturnType<typeof drizzle<typeof schema>>;
    20→
    21→let _db: DbClient | null = null;
    22→let _warned = false;
    23→let _lastInitAttempt = 0;
    24→const REINIT_COOLDOWN_MS = 15_000; // don't hammer a dead DB on every request
    25→
    26→export function getDb(): DbClient | null {
    27→  if (_db) return _db;
    28→
    29→  const url = process.env.DATABASE_URL;
    30→  if (!url) {
    31→    if (!_warned) {
    32→      logger.warn("[db] DATABASE_URL not set — DB persistence disabled");
    33→      _warned = true;
    34→    }
    35→    return null;
    36→  }
    37→
    38→  // If pool creation failed recently, don't retry on every single call —
    39→  // wait out the cooldown so a dead DB doesn't add latency to every request.
    40→  const now = Date.now();
    41→  if (now - _lastInitAttempt < REINIT_COOLDOWN_MS) {
    42→    return null;
    43→  }
    44→  _lastInitAttempt = now;
    45→
    46→  try {
    47→    const pool = new pg.Pool({ max: 5, connectionString: url });
    48→
    49→    // Pool-level errors (e.g. connection dropped by the DB host) would
    50→    // otherwise surface as an unhandled 'error' event and crash the process.
    51→    // Log and let getDb() naturally re-create the pool on the next call.
    52→    pool.on("error", (err) => {
    53→      logger.error({ err: err.message }, "[db] pool error — will retry on next access");
    54→      _db = null;
    55→    });
    56→
    57→    _db = drizzle(pool, { schema });
    58→    logger.info("[db] PostgreSQL connection pool initialised");
    59→    return _db;
    60→  } catch (err) {
    61→    logger.error({ err: (err as Error).message }, "[db] Failed to initialise pool");
    62→    return null;
    63→  }
    64→}
    65→
    66→/**
    67→ * Fire-and-forget DB write. Errors are logged but never thrown.
    68→ * The in-memory store is the source of truth for reads.
    69→ */
    70→export function dbRun(
    71→  label: string,
    72→  fn: (db: DbClient) => Promise<void>,
    73→): void {
    74→  const db = getDb();
    75→  if (!db) return;
    76→  fn(db).catch((err: Error) => {
    77→    logger.warn({ label, err: err.message }, "[db] shadow write failed");
    78→  });
    79→}
    80→
    81→/**
    82→ * Awaited DB read with typed fallback on error or when DB is unavailable.
    83→ * Use for startup hydration only — all runtime reads should use in-memory.
    84→ */
    85→export async function dbGet<T>(
    86→  label: string,
    87→  fn: (db: DbClient) => Promise<T>,
    88→  fallback: T,
    89→): Promise<T> {
    90→  const db = getDb();
    91→  if (!db) return fallback;
    92→  try {
    93→    return await fn(db);
    94→  } catch (err) {
    95→    logger.warn({ label, err: (err as Error).message }, "[db] read failed");
    96→    return fallback;
    97→  }
    98→}
    99→

