     1→/**
     2→ * Generic retry-with-backoff for transient failures (DB hiccups, flaky
     3→ * upstream HTTP calls). This is NOT a magic bug-fixer — it only helps when
     4→ * the underlying operation is safe to retry and the failure is transient
     5→ * (network blip, momentary connection drop). Logic errors will still fail
     6→ * every time, as they should.
     7→ *
     8→ * Usage:
     9→ *   const result = await withRetry(() => dbGet(...), { label: "load-user" });
    10→ */
    11→import { logger } from "./logger";
    12→
    13→interface RetryOptions {
    14→  label: string;
    15→  attempts?: number; // total attempts including the first try
    16→  baseDelayMs?: number; // delay before the first retry
    17→  maxDelayMs?: number; // cap on backoff delay
    18→}
    19→
    20→export async function withRetry<T>(
    21→  fn: () => Promise<T>,
    22→  { label, attempts = 3, baseDelayMs = 250, maxDelayMs = 4000 }: RetryOptions,
    23→): Promise<T> {
    24→  let lastErr: unknown;
    25→
    26→  for (let attempt = 1; attempt <= attempts; attempt++) {
    27→    try {
    28→      return await fn();
    29→    } catch (err) {
    30→      lastErr = err;
    31→      const isLastAttempt = attempt === attempts;
    32→      logger.warn(
    33→        { label, attempt, attempts, err: (err as Error)?.message },
    34→        isLastAttempt
    35→          ? "[retry] final attempt failed, giving up"
    36→          : "[retry] attempt failed, retrying",
    37→      );
    38→      if (isLastAttempt) break;
    39→
    40→      const delay = Math.min(baseDelayMs * 2 ** (attempt - 1), maxDelayMs);
    41→      await new Promise((resolve) => setTimeout(resolve, delay));
    42→    }
    43→  }
    44→
    45→  throw lastErr;
    46→}
