     1→/**
     2→ * Background sweeper. Runs every 30 seconds and:
     3→ *  - Expires withdrawals stuck in awaiting_gas_fee past their deadline,
     4→ *    refunding the held funds to the user's main wallet and emitting an
     5→ *    in-app notification + admin alert.
     6→ *
     7→ * Started once from server/index.ts; idempotent.
     8→ */
     9→import { logActivity, NOW, userData, users } from "./store";
    10→import { notifyUser, pushAdminAlert } from "./notify";
    11→import { logger } from "./logger";
    12→
    13→let started = false;
    14→
    15→function sweepOnce(): void {
    16→  const nowMs = Date.now();
    17→  for (const [userId, data] of userData) {
    18→    for (const wd of data.withdrawals) {
    19→      if (wd.status !== "awaiting_gas_fee") continue;
    20→      if (!wd.gasFeeDeadlineAt) continue;
    21→      const deadlineMs = Date.parse(wd.gasFeeDeadlineAt);
    22→      if (Number.isNaN(deadlineMs) || deadlineMs > nowMs) continue;
    23→
    24→      wd.status = "expired";
    25→      wd.decidedAt = NOW();
    26→      wd.rejectionReason = wd.rejectionReason ?? "Gas-fee deadline passed.";
    27→
    28→      // Release any held funds back to the main wallet (mirrors the reject path).
    29→      const main = data.wallets.find((w) => w.type === "main");
    30→      if (main) {
    31→        main.pendingBalance =
    32→          Math.round((main.pendingBalance - wd.amount) * 100) / 100;
    33→        main.balance = Math.round((main.balance + wd.amount) * 100) / 100;
    34→      }
    35→      const tx = data.transactions.find(
    36→        (t) =>
    37→          t.type === "withdrawal" &&
    38→          t.status === "pending" &&
    39→          Math.abs(t.amount) === wd.amount,
    40→      );
    41→      if (tx) tx.status = "failed";
    42→
    43→      const stored = users.get(userId);
    44→      notifyUser({
    45→        userId,
    46→        kind: "withdrawal_expired",
    47→        emailToggle: "withdrawalExpired",
    48→        title: "Withdrawal expired",
    49→        body: `Your withdrawal of ${wd.amount} ${wd.currency} expired because the gas-fee deadline passed. Funds were returned to your main wallet.`,
    50→        link: "/withdrawals",
    51→      });
    52→      pushAdminAlert({
    53→        kind: "withdrawal.expired",
    54→        title: "Withdrawal expired (gas-fee deadline)",
    55→        body: `Withdrawal ${wd.id} (${wd.amount} ${wd.currency}) for ${stored?.user.email ?? userId} expired before the user funded the gas fee.`,
    56→        userId,
    57→        userEmail: stored?.user.email ?? null,
    58→        severity: "warning",
    59→      });
    60→      logActivity({
    61→        actorId: "system",
    62→        actorName: "system.sweeper",
    63→        action: "withdrawal.expire",
    64→        detail: `Auto-expired withdrawal ${wd.id} for ${stored?.user.email ?? userId}.`,
