const fs = require('fs');
const path = require('path');

const catalog = {
  '@replit/vite-plugin-cartographer': '^0.5.1',
  '@replit/vite-plugin-dev-banner': '^0.1.1',
  '@replit/vite-plugin-runtime-error-modal': '^0.0.6',
  '@tailwindcss/vite': '^4.1.14',
  '@tanstack/react-query': '^5.90.21',
  '@types/node': '^25.3.3',
  '@types/react': '^19.2.0',
  '@types/react-dom': '^19.2.0',
  '@vitejs/plugin-react': '^5.0.4',
  'class-variance-authority': '^0.7.1',
  'clsx': '^2.1.1',
  'drizzle-orm': '^0.45.2',
  'framer-motion': '^12.23.24',
  'lucide-react': '^0.545.0',
  'react': '19.1.0',
  'react-dom': '19.1.0',
  'tailwind-merge': '^3.3.1',
  'tailwindcss': '^4.1.14',
  'tsx': '^4.21.0',
  'vite': '^7.3.2',
  'zod': '^3.25.76',
};

const pkgFiles = [
  '02-artifacts-api-server-db/artifacts/api-server/package.json',
  '07-lib-misc/lib/db/package.json',
  '07-lib-misc/lib/api-spec/package.json',
  '07-lib-misc/lib/api-client-react/package.json',
  '03-artifacts-admin-portal/artifacts/admin-portal/package.json',
  '04-artifacts-mockup-sandbox/artifacts/mockup-sandbox/package.json',
  '05-artifacts-nextrade-part1/artifacts/nextrade/package.json',
  '.merged/nextrade/package.json',
  '08-lib-api-zod-part1/lib/api-zod/package.json',
  '.merged/api-zod/package.json',
  '01-root-and-misc/scripts/package.json',
];

const root = '/home/runner/workspace';

function fixDeps(deps) {
  if (!deps) return deps;
  for (const [key, val] of Object.entries(deps)) {
    if (val === 'catalog:') {
      if (catalog[key] !== undefined) {
        deps[key] = catalog[key];
      } else {
        console.error(`  !! Unknown catalog entry: ${key}`);
      }
    }
    if (val === 'workspace:*') {
      deps[key] = '*';
    }
  }
  return deps;
}

for (const rel of pkgFiles) {
  const file = path.join(root, rel);
  const raw = fs.readFileSync(file, 'utf8');
  const pkg = JSON.parse(raw);

  pkg.dependencies = fixDeps(pkg.dependencies);
  pkg.devDependencies = fixDeps(pkg.devDependencies);
  pkg.peerDependencies = fixDeps(pkg.peerDependencies);

  // Fix api-server dev script: pnpm run -> npm run
  if (pkg.name === '@workspace/api-server' && pkg.scripts?.dev) {
    pkg.scripts.dev = 'NODE_ENV=development npm run build && npm run start';
  }

  // Fix api-spec codegen script
  if (pkg.name === '@workspace/api-spec' && pkg.scripts?.codegen) {
    pkg.scripts.codegen = pkg.scripts.codegen.replace(
      'pnpm -w run typecheck:libs',
      'npm run typecheck --workspaces --if-present'
    );
  }

  fs.writeFileSync(file, JSON.stringify(pkg, null, 2) + '\n', 'utf8');
  console.log(`✓ ${rel}`);
}
EOF

